class Solution:
    def canConvertString(self, s: str, t: str, k: int) -> bool:
        if s == t:
            return True
        if len(s) != len(t):
            return False
        s_count = [0] * 26
        t_count = [0] * 26
        for i in range(len(s)):
            s_count[ord(s[i]) - ord('a')] += 1
            t_count[ord(t[i]) - ord('a')] += 1
        for i in range(26):
            if s_count[i] != t_count[i]:
                diff = abs(s_count[i] - t_count[i])
                if k < diff:
                    return False
                k -= diff
        return True
